//! Rust facades for selected AngularTS services.
//!
//! These types intentionally expose only the MVP method surface. Browser runtime
//! calls are available on `wasm32` through `wasm-bindgen` extern bindings; host
//! tests use the portable data types and service token metadata.

use std::collections::BTreeMap;
#[cfg(not(target_arch = "wasm32"))]
use std::collections::HashMap;

/// Marker trait generated by `#[service]`.
pub trait Service {
    const TOKEN_NAME: &'static str;
    const EXPORT_NAME: &'static str;
}

/// Built-in persistent storage backends understood by AngularTS store registration.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum StorageType {
    Local,
    Session,
    Cookie,
    Custom,
}

impl StorageType {
    /// Returns the storage type string used by AngularTS metadata.
    pub const fn as_str(self) -> &'static str {
        match self {
            Self::Local => "local",
            Self::Session => "session",
            Self::Cookie => "cookie",
            Self::Custom => "custom",
        }
    }
}

/// Rust trait equivalent of the public AngularTS `StorageBackend` interface.
pub trait StorageBackend {
    /// Reads a stored serialized value.
    fn get(&self, key: &str) -> Option<String>;

    /// Stores a serialized value.
    fn set(&mut self, key: &str, value: &str);

    /// Removes a stored value.
    fn remove(&mut self, key: &str);
}

/// Machine mode name used by AngularTS `$machine`.
pub type MachineMode = String;

/// Event name to payload metadata map for Rust-authored machine declarations.
pub type MachineEventMap = BTreeMap<String, String>;

/// Result returned by a Rust machine transition.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum MachineTransitionResult {
    /// Transition to the supplied mode.
    Mode(MachineMode),
    /// Keep the current mode after running transition effects.
    Stay,
}

impl MachineTransitionResult {
    /// Creates a transition result that moves to `mode`.
    pub fn mode(mode: impl Into<String>) -> Self {
        let mode = mode.into();

        if mode.is_empty() {
            Self::Stay
        } else {
            Self::Mode(mode)
        }
    }
}

impl From<&str> for MachineTransitionResult {
    fn from(mode: &str) -> Self {
        Self::mode(mode)
    }
}

impl From<String> for MachineTransitionResult {
    fn from(mode: String) -> Self {
        Self::mode(mode)
    }
}

/// Transition callback for a Rust-authored machine.
pub type MachineTransition<TData, TPayload = ()> =
    fn(&mut TData, &TPayload) -> MachineTransitionResult;

/// Transition table keyed by current mode and event type.
pub type MachineTransitionMap<TData, TPayload = ()> =
    BTreeMap<MachineMode, BTreeMap<String, MachineTransition<TData, TPayload>>>;

/// Context passed to Rust machine hooks.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct MachineTransitionContext<'a, TData, TPayload = ()> {
    event_type: &'a str,
    from: &'a str,
    to: &'a str,
    payload: &'a TPayload,
    data: &'a TData,
}

impl<'a, TData, TPayload> MachineTransitionContext<'a, TData, TPayload> {
    /// Creates a transition context.
    pub const fn new(
        event_type: &'a str,
        from: &'a str,
        to: &'a str,
        payload: &'a TPayload,
        data: &'a TData,
    ) -> Self {
        Self {
            event_type,
            from,
            to,
            payload,
            data,
        }
    }

    /// Event type that triggered the transition.
    pub const fn event_type(&self) -> &str {
        self.event_type
    }

    /// Mode before the transition.
    pub const fn from(&self) -> &str {
        self.from
    }

    /// Mode after the transition.
    pub const fn to(&self) -> &str {
        self.to
    }

    /// Transition payload.
    pub const fn payload(&self) -> &TPayload {
        self.payload
    }

    /// Machine data after transition effects have run.
    pub const fn data(&self) -> &TData {
        self.data
    }
}

/// Hook callback for a Rust-authored machine transition.
pub type MachineTransitionHook<TData, TPayload = ()> =
    for<'a> fn(&MachineTransitionContext<'a, TData, TPayload>);

/// Mode-specific hook map keyed by mode.
pub type MachineModeHooks<TData, TPayload = ()> =
    BTreeMap<MachineMode, MachineTransitionHook<TData, TPayload>>;

/// Hook callbacks for a Rust-authored machine.
#[derive(Clone, Default)]
pub struct MachineHooks<TData, TPayload = ()> {
    enter: MachineModeHooks<TData, TPayload>,
    exit: MachineModeHooks<TData, TPayload>,
    transition: Option<MachineTransitionHook<TData, TPayload>>,
}

impl<TData, TPayload> MachineHooks<TData, TPayload> {
    /// Creates empty machine hooks.
    pub fn new() -> Self {
        Self {
            enter: BTreeMap::new(),
            exit: BTreeMap::new(),
            transition: None,
        }
    }

    /// Registers an enter hook for `mode`.
    pub fn on_enter(
        mut self,
        mode: impl Into<String>,
        hook: MachineTransitionHook<TData, TPayload>,
    ) -> Self {
        self.enter.insert(mode.into(), hook);
        self
    }

    /// Registers an exit hook for `mode`.
    pub fn on_exit(
        mut self,
        mode: impl Into<String>,
        hook: MachineTransitionHook<TData, TPayload>,
    ) -> Self {
        self.exit.insert(mode.into(), hook);
        self
    }

    /// Registers a hook that runs after every handled transition.
    pub const fn on_transition(mut self, hook: MachineTransitionHook<TData, TPayload>) -> Self {
        self.transition = Some(hook);
        self
    }

    /// Enter hooks.
    pub const fn enter(&self) -> &MachineModeHooks<TData, TPayload> {
        &self.enter
    }

    /// Exit hooks.
    pub const fn exit(&self) -> &MachineModeHooks<TData, TPayload> {
        &self.exit
    }

    /// Transition hook, when configured.
    pub const fn transition(&self) -> Option<MachineTransitionHook<TData, TPayload>> {
        self.transition
    }
}

/// Config for a Rust-authored machine.
#[derive(Clone)]
pub struct MachineConfig<TData, TPayload = ()> {
    initial: MachineMode,
    data: TData,
    transitions: MachineTransitionMap<TData, TPayload>,
    hooks: MachineHooks<TData, TPayload>,
}

impl<TData, TPayload> MachineConfig<TData, TPayload> {
    /// Creates a machine config with initial mode and data.
    pub fn new(initial: impl Into<String>, data: TData) -> Self {
        Self {
            initial: initial.into(),
            data,
            transitions: BTreeMap::new(),
            hooks: MachineHooks::new(),
        }
    }

    /// Initial mode.
    pub fn initial(&self) -> &str {
        &self.initial
    }

    /// Initial data.
    pub const fn data(&self) -> &TData {
        &self.data
    }

    /// Transition table.
    pub const fn transitions(&self) -> &MachineTransitionMap<TData, TPayload> {
        &self.transitions
    }

    /// Hook config.
    pub const fn hooks(&self) -> &MachineHooks<TData, TPayload> {
        &self.hooks
    }

    /// Adds a transition for a mode and event type.
    pub fn transition(
        mut self,
        mode: impl Into<String>,
        event_type: impl Into<String>,
        transition: MachineTransition<TData, TPayload>,
    ) -> Self {
        self.transitions
            .entry(mode.into())
            .or_default()
            .insert(event_type.into(), transition);
        self
    }

    /// Replaces machine hooks.
    pub fn with_hooks(mut self, hooks: MachineHooks<TData, TPayload>) -> Self {
        self.hooks = hooks;
        self
    }
}

/// Serializable snapshot for a machine's current mode and data.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct MachineSnapshot<TData> {
    current: MachineMode,
    data: TData,
}

impl<TData> MachineSnapshot<TData> {
    /// Creates a machine snapshot.
    pub fn new(current: impl Into<String>, data: TData) -> Self {
        Self {
            current: current.into(),
            data,
        }
    }

    /// Snapshot mode.
    pub fn current(&self) -> &str {
        &self.current
    }

    /// Snapshot data.
    pub const fn data(&self) -> &TData {
        &self.data
    }

    /// Consumes the snapshot into its data value.
    pub fn into_data(self) -> TData {
        self.data
    }
}

/// Small Rust-native machine runtime matching AngularTS `$machine` semantics.
pub struct Machine<TData, TPayload = ()> {
    current: MachineMode,
    data: TData,
    transitions: MachineTransitionMap<TData, TPayload>,
    hooks: MachineHooks<TData, TPayload>,
}

impl<TData, TPayload> Machine<TData, TPayload> {
    /// Creates a machine from config.
    pub fn new(config: MachineConfig<TData, TPayload>) -> Self {
        Self {
            current: config.initial,
            data: config.data,
            transitions: config.transitions,
            hooks: config.hooks,
        }
    }

    /// Current mode.
    pub fn current(&self) -> &str {
        &self.current
    }

    /// Machine data.
    pub const fn data(&self) -> &TData {
        &self.data
    }

    /// Mutable machine data.
    pub fn data_mut(&mut self) -> &mut TData {
        &mut self.data
    }

    /// Returns whether the current mode has a handler for `event_type`.
    pub fn can(&self, event_type: &str) -> bool {
        self.transitions
            .get(&self.current)
            .is_some_and(|transitions| transitions.contains_key(event_type))
    }

    /// Returns whether the machine is currently in `mode`.
    pub fn matches(&self, mode: &str) -> bool {
        self.current == mode
    }

    /// Sends an event to the machine. Returns true when a handler ran.
    pub fn send(&mut self, event_type: &str, payload: TPayload) -> bool {
        let Some(transition) = self
            .transitions
            .get(&self.current)
            .and_then(|transitions| transitions.get(event_type))
            .copied()
        else {
            return false;
        };

        let from = self.current.clone();
        let result = transition(&mut self.data, &payload);
        let to = match result {
            MachineTransitionResult::Mode(mode) if !mode.is_empty() => mode,
            _ => from.clone(),
        };
        let context = MachineTransitionContext::new(event_type, &from, &to, &payload, &self.data);

        if from != to {
            if let Some(hook) = self.hooks.exit.get(&from) {
                hook(&context);
            }
        }

        self.current = to.clone();

        if from != to {
            if let Some(hook) = self.hooks.enter.get(&to) {
                hook(&context);
            }
        }

        if let Some(hook) = self.hooks.transition {
            hook(&context);
        }

        true
    }
}

impl<TData: Clone, TPayload> Machine<TData, TPayload> {
    /// Captures the current mode and cloned data.
    pub fn snapshot(&self) -> MachineSnapshot<TData> {
        MachineSnapshot::new(self.current.clone(), self.data.clone())
    }

    /// Restores the current mode and data from a snapshot.
    pub fn restore(&mut self, snapshot: MachineSnapshot<TData>) {
        self.current = snapshot.current;
        self.data = snapshot.data;
    }
}

/// Config-free provider facade for AngularTS `$machine`.
#[derive(Debug, Clone, Copy, Default)]
pub struct MachineProvider;

impl MachineProvider {
    /// Provider token used during AngularTS config-time injection.
    pub const PROVIDER_TOKEN_NAME: &'static str = "$machineProvider";

    /// Runtime service token produced by this provider.
    pub const SERVICE_TOKEN_NAME: &'static str = "$machine";

    /// Creates a provider facade.
    pub const fn new() -> Self {
        Self
    }

    /// Creates a Rust-native machine from config.
    pub fn create<TData, TPayload>(
        &self,
        config: MachineConfig<TData, TPayload>,
    ) -> Machine<TData, TPayload> {
        Machine::new(config)
    }
}

/// In-memory storage backend useful for tests and custom Rust stores.
#[cfg(not(target_arch = "wasm32"))]
#[derive(Debug, Clone, Default)]
pub struct MemoryStorageBackend {
    values: HashMap<String, String>,
}

#[cfg(not(target_arch = "wasm32"))]
impl MemoryStorageBackend {
    /// Creates an empty memory storage backend.
    pub fn new() -> Self {
        Self::default()
    }

    /// Returns stored key count.
    pub fn len(&self) -> usize {
        self.values.len()
    }

    /// Returns whether the backend is empty.
    pub fn is_empty(&self) -> bool {
        self.values.is_empty()
    }
}

#[cfg(not(target_arch = "wasm32"))]
impl StorageBackend for MemoryStorageBackend {
    fn get(&self, key: &str) -> Option<String> {
        self.values.get(key).cloned()
    }

    fn set(&mut self, key: &str, value: &str) {
        self.values.insert(key.to_string(), value.to_string());
    }

    fn remove(&mut self, key: &str) {
        self.values.remove(key);
    }
}

/// SameSite policy applied by the browser for a cookie write.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum CookieSameSite {
    Lax,
    Strict,
    None,
}

impl CookieSameSite {
    /// Returns the SameSite string used by AngularTS cookie options.
    pub const fn as_str(self) -> &'static str {
        match self {
            Self::Lax => "Lax",
            Self::Strict => "Strict",
            Self::None => "None",
        }
    }
}

/// Rust representation of AngularTS cookie write options.
#[derive(Debug, Clone, PartialEq, Eq, Default)]
pub struct CookieOptions {
    path: Option<String>,
    domain: Option<String>,
    expires: Option<String>,
    secure: bool,
    same_site: Option<CookieSameSite>,
}

impl CookieOptions {
    /// Creates empty cookie options.
    pub fn new() -> Self {
        Self::default()
    }

    /// Returns the cookie path, when set.
    pub fn path(&self) -> Option<&str> {
        self.path.as_deref()
    }

    /// Returns the cookie domain, when set.
    pub fn domain(&self) -> Option<&str> {
        self.domain.as_deref()
    }

    /// Returns the cookie expiration value, when set.
    pub fn expires(&self) -> Option<&str> {
        self.expires.as_deref()
    }

    /// Returns whether the cookie should be restricted to HTTPS.
    pub const fn secure(&self) -> bool {
        self.secure
    }

    /// Returns the SameSite policy, when set.
    pub const fn same_site(&self) -> Option<CookieSameSite> {
        self.same_site
    }

    /// Sets the cookie path.
    pub fn with_path(mut self, path: impl Into<String>) -> Self {
        self.path = Some(path.into());
        self
    }

    /// Sets the cookie domain.
    pub fn with_domain(mut self, domain: impl Into<String>) -> Self {
        self.domain = Some(domain.into());
        self
    }

    /// Sets the cookie expiration value.
    pub fn with_expires(mut self, expires: impl Into<String>) -> Self {
        self.expires = Some(expires.into());
        self
    }

    /// Sets whether the cookie should be restricted to HTTPS.
    pub const fn with_secure(mut self, secure: bool) -> Self {
        self.secure = secure;
        self
    }

    /// Sets the SameSite policy.
    pub const fn with_same_site(mut self, same_site: CookieSameSite) -> Self {
        self.same_site = Some(same_site);
        self
    }

    /// Converts this config into the JavaScript object accepted by `$cookie`.
    #[cfg(target_arch = "wasm32")]
    pub fn to_js_value(&self) -> Result<wasm_bindgen::JsValue, wasm_bindgen::JsValue> {
        use js_sys::{Object, Reflect};
        use wasm_bindgen::JsValue;

        let options = Object::new();

        if let Some(path) = &self.path {
            Reflect::set(
                &options,
                &JsValue::from_str("path"),
                &JsValue::from_str(path),
            )?;
        }
        if let Some(domain) = &self.domain {
            Reflect::set(
                &options,
                &JsValue::from_str("domain"),
                &JsValue::from_str(domain),
            )?;
        }
        if let Some(expires) = &self.expires {
            Reflect::set(
                &options,
                &JsValue::from_str("expires"),
                &JsValue::from_str(expires),
            )?;
        }
        if self.secure {
            Reflect::set(
                &options,
                &JsValue::from_str("secure"),
                &JsValue::from_bool(true),
            )?;
        }
        if let Some(same_site) = self.same_site {
            Reflect::set(
                &options,
                &JsValue::from_str("samesite"),
                &JsValue::from_str(same_site.as_str()),
            )?;
        }

        Ok(options.into())
    }
}

/// Rust representation of options for cookie-backed persistent stores.
#[derive(Debug, Clone, PartialEq, Eq, Default)]
pub struct CookieStoreOptions {
    cookie: Option<CookieOptions>,
}

impl CookieStoreOptions {
    /// Creates empty cookie store options.
    pub fn new() -> Self {
        Self::default()
    }

    /// Returns cookie write options, when configured.
    pub const fn cookie(&self) -> Option<&CookieOptions> {
        self.cookie.as_ref()
    }

    /// Sets cookie write options.
    pub fn with_cookie(mut self, cookie: CookieOptions) -> Self {
        self.cookie = Some(cookie);
        self
    }
}

/// HTTP verb accepted by AngularTS `$http`.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum HttpMethod {
    Get,
    Post,
    Put,
    Delete,
    Patch,
    Head,
    Options,
}

impl HttpMethod {
    /// Returns the uppercase method string used by AngularTS request configs.
    pub const fn as_str(self) -> &'static str {
        match self {
            Self::Get => "GET",
            Self::Post => "POST",
            Self::Put => "PUT",
            Self::Delete => "DELETE",
            Self::Patch => "PATCH",
            Self::Head => "HEAD",
            Self::Options => "OPTIONS",
        }
    }

    /// Converts the uppercase method string used by AngularTS request configs.
    pub fn from_angular(value: &str) -> Option<Self> {
        match value {
            "GET" => Some(Self::Get),
            "POST" => Some(Self::Post),
            "PUT" => Some(Self::Put),
            "DELETE" => Some(Self::Delete),
            "PATCH" => Some(Self::Patch),
            "HEAD" => Some(Self::Head),
            "OPTIONS" => Some(Self::Options),
            _ => None,
        }
    }
}

/// Minimal Rust representation of an AngularTS state declaration.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct StateDeclaration {
    name: String,
    url: Option<String>,
    component: Option<String>,
    template: Option<String>,
    template_url: Option<String>,
    abstract_state: bool,
}

impl StateDeclaration {
    /// Creates a state declaration with the required state name.
    pub fn new(name: impl Into<String>) -> Self {
        Self {
            name: name.into(),
            url: None,
            component: None,
            template: None,
            template_url: None,
            abstract_state: false,
        }
    }

    /// State name.
    pub fn name(&self) -> &str {
        &self.name
    }

    /// URL fragment for this state, when configured.
    pub fn url(&self) -> Option<&str> {
        self.url.as_deref()
    }

    /// Component name for this state's default view, when configured.
    pub fn component(&self) -> Option<&str> {
        self.component.as_deref()
    }

    /// Inline template for this state's default view, when configured.
    pub fn template(&self) -> Option<&str> {
        self.template.as_deref()
    }

    /// Template URL for this state's default view, when configured.
    pub fn template_url(&self) -> Option<&str> {
        self.template_url.as_deref()
    }

    /// Whether this is an abstract state.
    pub const fn abstract_state(&self) -> bool {
        self.abstract_state
    }

    /// Sets the state URL fragment.
    pub fn with_url(mut self, url: impl Into<String>) -> Self {
        self.url = Some(url.into());
        self
    }

    /// Sets the component name for the default view.
    pub fn with_component(mut self, component: impl Into<String>) -> Self {
        self.component = Some(component.into());
        self
    }

    /// Sets the inline template for the default view.
    pub fn with_template(mut self, template: impl Into<String>) -> Self {
        self.template = Some(template.into());
        self
    }

    /// Sets the template URL for the default view.
    pub fn with_template_url(mut self, template_url: impl Into<String>) -> Self {
        self.template_url = Some(template_url.into());
        self
    }

    /// Marks this state as abstract or concrete.
    pub const fn with_abstract(mut self, abstract_state: bool) -> Self {
        self.abstract_state = abstract_state;
        self
    }

    /// Converts this declaration into the JavaScript object accepted by `$stateRegistry`.
    #[cfg(target_arch = "wasm32")]
    pub fn to_js_value(&self) -> Result<wasm_bindgen::JsValue, wasm_bindgen::JsValue> {
        use js_sys::{Object, Reflect};
        use wasm_bindgen::JsValue;

        let state = Object::new();

        Reflect::set(
            &state,
            &JsValue::from_str("name"),
            &JsValue::from_str(&self.name),
        )?;

        if let Some(url) = &self.url {
            Reflect::set(&state, &JsValue::from_str("url"), &JsValue::from_str(url))?;
        }

        if let Some(component) = &self.component {
            Reflect::set(
                &state,
                &JsValue::from_str("component"),
                &JsValue::from_str(component),
            )?;
        }

        if let Some(template) = &self.template {
            Reflect::set(
                &state,
                &JsValue::from_str("template"),
                &JsValue::from_str(template),
            )?;
        }

        if let Some(template_url) = &self.template_url {
            Reflect::set(
                &state,
                &JsValue::from_str("templateUrl"),
                &JsValue::from_str(template_url),
            )?;
        }

        if self.abstract_state {
            Reflect::set(
                &state,
                &JsValue::from_str("abstract"),
                &JsValue::from_bool(true),
            )?;
        }

        Ok(state.into())
    }
}

/// Minimal resolve metadata for Rust-authored state declarations.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct StateResolve {
    token: String,
    deps: Vec<String>,
    eager: bool,
}

impl StateResolve {
    /// Creates a resolve declaration for a token.
    pub fn new(token: impl Into<String>) -> Self {
        Self {
            token: token.into(),
            deps: Vec::new(),
            eager: false,
        }
    }

    /// Resolve token.
    pub fn token(&self) -> &str {
        &self.token
    }

    /// Dependency tokens used by the resolve.
    pub fn deps(&self) -> &[String] {
        &self.deps
    }

    /// Whether the resolve should start eagerly.
    pub const fn eager(&self) -> bool {
        self.eager
    }

    /// Adds a dependency token.
    pub fn dep(mut self, dep: impl Into<String>) -> Self {
        self.deps.push(dep.into());
        self
    }

    /// Sets the eager flag.
    pub const fn with_eager(mut self, eager: bool) -> Self {
        self.eager = eager;
        self
    }
}

/// Rust representation of AngularTS object-style state resolves.
pub type StateResolveObject = Vec<StateResolve>;

/// Rust representation of AngularTS array-style state resolves.
pub type StateResolveArray = Vec<StateResolve>;

/// Realtime DOM/content swap modes understood by AngularTS realtime directives.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SwapModeType {
    InnerHtml,
    OuterHtml,
    TextContent,
    BeforeBegin,
    AfterBegin,
    BeforeEnd,
    AfterEnd,
    Delete,
    None,
}

impl SwapModeType {
    /// Returns the swap string used by AngularTS realtime protocol messages.
    pub const fn as_str(self) -> &'static str {
        match self {
            Self::InnerHtml => "innerHTML",
            Self::OuterHtml => "outerHTML",
            Self::TextContent => "textContent",
            Self::BeforeBegin => "beforebegin",
            Self::AfterBegin => "afterbegin",
            Self::BeforeEnd => "beforeend",
            Self::AfterEnd => "afterend",
            Self::Delete => "delete",
            Self::None => "none",
        }
    }

    /// Converts a realtime protocol swap string.
    pub fn from_angular(value: &str) -> Option<Self> {
        match value {
            "innerHTML" => Some(Self::InnerHtml),
            "outerHTML" => Some(Self::OuterHtml),
            "textContent" => Some(Self::TextContent),
            "beforebegin" => Some(Self::BeforeBegin),
            "afterbegin" => Some(Self::AfterBegin),
            "beforeend" => Some(Self::BeforeEnd),
            "afterend" => Some(Self::AfterEnd),
            "delete" => Some(Self::Delete),
            "none" => Some(Self::None),
            _ => None,
        }
    }
}

/// Rust representation of AngularTS shared realtime connection options.
#[derive(Debug, Clone, PartialEq, Eq, Default)]
pub struct ConnectionConfig {
    retry_delay: Option<u32>,
    max_retries: Option<u32>,
    heartbeat_timeout: Option<u32>,
    event_types: Vec<String>,
}

impl ConnectionConfig {
    /// Creates empty connection options.
    pub fn new() -> Self {
        Self::default()
    }

    /// Optional delay between reconnect attempts in milliseconds.
    pub const fn retry_delay(&self) -> Option<u32> {
        self.retry_delay
    }

    /// Optional maximum reconnect attempt count.
    pub const fn max_retries(&self) -> Option<u32> {
        self.max_retries
    }

    /// Optional heartbeat timeout in milliseconds.
    pub const fn heartbeat_timeout(&self) -> Option<u32> {
        self.heartbeat_timeout
    }

    /// Additional SSE event types.
    pub fn event_types(&self) -> &[String] {
        &self.event_types
    }

    /// Sets reconnect delay in milliseconds.
    pub const fn retry_delay_ms(mut self, retry_delay: u32) -> Self {
        self.retry_delay = Some(retry_delay);
        self
    }

    /// Sets maximum reconnect attempts.
    pub const fn with_max_retries(mut self, max_retries: u32) -> Self {
        self.max_retries = Some(max_retries);
        self
    }

    /// Sets heartbeat timeout in milliseconds.
    pub const fn heartbeat_timeout_ms(mut self, heartbeat_timeout: u32) -> Self {
        self.heartbeat_timeout = Some(heartbeat_timeout);
        self
    }

    /// Adds an extra event type to subscribe to.
    pub fn event_type(mut self, event_type: impl Into<String>) -> Self {
        self.event_types.push(event_type.into());
        self
    }

    /// Converts this config into the JavaScript object accepted by realtime services.
    #[cfg(target_arch = "wasm32")]
    pub fn to_js_value(&self) -> Result<wasm_bindgen::JsValue, wasm_bindgen::JsValue> {
        use js_sys::{Array, Object, Reflect};
        use wasm_bindgen::JsValue;

        let config = Object::new();

        if let Some(retry_delay) = self.retry_delay {
            Reflect::set(
                &config,
                &JsValue::from_str("retryDelay"),
                &JsValue::from_f64(retry_delay as f64),
            )?;
        }

        if let Some(max_retries) = self.max_retries {
            Reflect::set(
                &config,
                &JsValue::from_str("maxRetries"),
                &JsValue::from_f64(max_retries as f64),
            )?;
        }

        if let Some(heartbeat_timeout) = self.heartbeat_timeout {
            Reflect::set(
                &config,
                &JsValue::from_str("heartbeatTimeout"),
                &JsValue::from_f64(heartbeat_timeout as f64),
            )?;
        }

        if !self.event_types.is_empty() {
            let event_types = Array::new();
            for event_type in &self.event_types {
                event_types.push(&JsValue::from_str(event_type));
            }
            Reflect::set(&config, &JsValue::from_str("eventTypes"), &event_types)?;
        }

        Ok(config.into())
    }
}

