/// Final transport status reported by AngularTS `$http`.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum HttpResponseStatus {
    Complete,
    Error,
    Timeout,
    Abort,
}

impl HttpResponseStatus {
    /// Returns the lowercase status string used by AngularTS responses.
    pub const fn as_str(self) -> &'static str {
        match self {
            Self::Complete => "complete",
            Self::Error => "error",
            Self::Timeout => "timeout",
            Self::Abort => "abort",
        }
    }

    /// Converts the lowercase status string used by AngularTS responses.
    pub fn from_angular(value: &str) -> Self {
        match value {
            "error" => Self::Error,
            "timeout" => Self::Timeout,
            "abort" => Self::Abort,
            _ => Self::Complete,
        }
    }
}

/// Rust representation of options accepted by AngularTS `$http` shortcut methods.
#[derive(Debug, Clone, PartialEq, Eq, Default)]
pub struct RequestShortcutConfig {
    headers: Vec<(String, String)>,
    params: Vec<(String, String)>,
    timeout: Option<u32>,
    response_type: Option<String>,
    with_credentials: Option<bool>,
}

impl RequestShortcutConfig {
    /// Creates an empty shortcut request config.
    pub fn new() -> Self {
        Self::default()
    }

    /// Adds or replaces one request header.
    pub fn header(mut self, name: impl Into<String>, value: impl Into<String>) -> Self {
        replace_pair(&mut self.headers, name.into(), value.into());
        self
    }

    /// Adds or replaces one query parameter.
    pub fn param(mut self, name: impl Into<String>, value: impl ToString) -> Self {
        replace_pair(&mut self.params, name.into(), value.to_string());
        self
    }

    /// Sets a millisecond request timeout.
    pub fn timeout_ms(mut self, timeout: u32) -> Self {
        self.timeout = Some(timeout);
        self
    }

    /// Sets the response body reader hint, such as `json` or `text`.
    pub fn response_type(mut self, response_type: impl Into<String>) -> Self {
        self.response_type = Some(response_type.into());
        self
    }

    /// Sets whether cross-site requests should include credentials.
    pub fn with_credentials(mut self, with_credentials: bool) -> Self {
        self.with_credentials = Some(with_credentials);
        self
    }

    /// Request headers.
    pub fn headers(&self) -> &[(String, String)] {
        &self.headers
    }

    /// Query parameters.
    pub fn params(&self) -> &[(String, String)] {
        &self.params
    }

    /// Optional millisecond timeout.
    pub const fn timeout(&self) -> Option<u32> {
        self.timeout
    }

    /// Optional response body reader hint.
    pub fn response_type_value(&self) -> Option<&str> {
        self.response_type.as_deref()
    }

    /// Optional credentials flag.
    pub const fn credentials(&self) -> Option<bool> {
        self.with_credentials
    }

    /// Converts this config into the JavaScript object accepted by `$http`.
    #[cfg(target_arch = "wasm32")]
    pub fn to_js_value(&self) -> Result<wasm_bindgen::JsValue, wasm_bindgen::JsValue> {
        use js_sys::Object;

        let config = Object::new();
        self.write_to_js_object(&config)?;

        Ok(config.into())
    }

    #[cfg(target_arch = "wasm32")]
    fn write_to_js_object(&self, config: &js_sys::Object) -> Result<(), wasm_bindgen::JsValue> {
        use js_sys::{Object, Reflect};
        use wasm_bindgen::JsValue;

        if !self.headers.is_empty() {
            let headers = Object::new();
            for (name, value) in &self.headers {
                Reflect::set(
                    &headers,
                    &JsValue::from_str(name),
                    &JsValue::from_str(value),
                )?;
            }
            Reflect::set(config, &JsValue::from_str("headers"), &headers)?;
        }

        if !self.params.is_empty() {
            let params = Object::new();
            for (name, value) in &self.params {
                Reflect::set(&params, &JsValue::from_str(name), &JsValue::from_str(value))?;
            }
            Reflect::set(config, &JsValue::from_str("params"), &params)?;
        }

        if let Some(timeout) = self.timeout {
            Reflect::set(
                config,
                &JsValue::from_str("timeout"),
                &JsValue::from_f64(timeout as f64),
            )?;
        }

        if let Some(response_type) = &self.response_type {
            Reflect::set(
                config,
                &JsValue::from_str("responseType"),
                &JsValue::from_str(response_type),
            )?;
        }

        if let Some(with_credentials) = self.with_credentials {
            Reflect::set(
                config,
                &JsValue::from_str("withCredentials"),
                &JsValue::from_bool(with_credentials),
            )?;
        }

        Ok(())
    }
}

/// Minimal Rust representation of an AngularTS `$http` request config.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RequestConfig {
    method: HttpMethod,
    url: String,
    shortcut: RequestShortcutConfig,
}

impl RequestConfig {
    /// Creates a request config for the given HTTP method and URL.
    pub fn new(method: HttpMethod, url: impl Into<String>) -> Self {
        Self {
            method,
            url: url.into(),
            shortcut: RequestShortcutConfig::new(),
        }
    }

    /// Creates a `GET` request config.
    pub fn get(url: impl Into<String>) -> Self {
        Self::new(HttpMethod::Get, url)
    }

    /// Creates a `POST` request config.
    pub fn post(url: impl Into<String>) -> Self {
        Self::new(HttpMethod::Post, url)
    }

    /// Adds or replaces one request header.
    pub fn header(mut self, name: impl Into<String>, value: impl Into<String>) -> Self {
        self.shortcut = self.shortcut.header(name, value);
        self
    }

    /// Adds or replaces one query parameter.
    pub fn param(mut self, name: impl Into<String>, value: impl ToString) -> Self {
        self.shortcut = self.shortcut.param(name, value);
        self
    }

    /// Sets a millisecond request timeout.
    pub fn timeout_ms(mut self, timeout: u32) -> Self {
        self.shortcut = self.shortcut.timeout_ms(timeout);
        self
    }

    /// Sets the response body reader hint, such as `json` or `text`.
    pub fn response_type(mut self, response_type: impl Into<String>) -> Self {
        self.shortcut = self.shortcut.response_type(response_type);
        self
    }

    /// Sets whether cross-site requests should include credentials.
    pub fn with_credentials(mut self, with_credentials: bool) -> Self {
        self.shortcut = self.shortcut.with_credentials(with_credentials);
        self
    }

    /// HTTP method for this request.
    pub const fn method(&self) -> HttpMethod {
        self.method
    }

    /// Request URL.
    pub fn url(&self) -> &str {
        &self.url
    }

    /// Request headers.
    pub fn headers(&self) -> &[(String, String)] {
        self.shortcut.headers()
    }

    /// Query parameters.
    pub fn params(&self) -> &[(String, String)] {
        self.shortcut.params()
    }

    /// Optional millisecond timeout.
    pub const fn timeout(&self) -> Option<u32> {
        self.shortcut.timeout()
    }

    /// Optional response body reader hint.
    pub fn response_type_value(&self) -> Option<&str> {
        self.shortcut.response_type_value()
    }

    /// Optional credentials flag.
    pub const fn credentials(&self) -> Option<bool> {
        self.shortcut.credentials()
    }

    /// Shortcut-method options embedded in this full request config.
    pub const fn shortcut(&self) -> &RequestShortcutConfig {
        &self.shortcut
    }

    /// Converts this config into the JavaScript object accepted by `$http`.
    #[cfg(target_arch = "wasm32")]
    pub fn to_js_value(&self) -> Result<wasm_bindgen::JsValue, wasm_bindgen::JsValue> {
        use js_sys::{Object, Reflect};
        use wasm_bindgen::JsValue;

        let config = Object::new();

        Reflect::set(
            &config,
            &JsValue::from_str("method"),
            &JsValue::from_str(self.method.as_str()),
        )?;
        Reflect::set(
            &config,
            &JsValue::from_str("url"),
            &JsValue::from_str(&self.url),
        )?;

        self.shortcut.write_to_js_object(&config)?;

        Ok(config.into())
    }
}

fn replace_pair(values: &mut Vec<(String, String)>, name: String, value: String) {
    if let Some((_, existing)) = values.iter_mut().find(|(key, _)| key == &name) {
        *existing = value;
    } else {
        values.push((name, value));
    }
}

