    impl CookieService {
        /// Creates an empty cookie service using default write options.
        pub fn new(defaults: CookieOptions) -> Self {
            Self {
                values: HashMap::new(),
                defaults,
            }
        }

        /// Returns the default cookie options.
        pub const fn defaults(&self) -> &CookieOptions {
            &self.defaults
        }

        /// Retrieves a raw cookie value.
        pub fn get(&self, key: &str) -> Option<&str> {
            self.values.get(key).map(String::as_str)
        }

        /// Returns all raw cookies.
        pub fn get_all(&self) -> &HashMap<String, String> {
            &self.values
        }

        /// Sets a raw cookie value.
        pub fn put(&mut self, key: impl Into<String>, value: impl Into<String>) {
            self.values.insert(key.into(), value.into());
        }

        /// Removes a cookie value.
        pub fn remove(&mut self, key: &str) {
            self.values.remove(key);
        }
    }

    impl TemplateCacheService {
        /// Creates an empty template cache.
        pub fn new() -> Self {
            Self::default()
        }

        /// Returns a cached template by URL.
        pub fn get(&self, url: &str) -> Option<&str> {
            self.templates.get(url).map(String::as_str)
        }

        /// Stores a template by URL.
        pub fn set(&mut self, url: impl Into<String>, template: impl Into<String>) {
            self.templates.insert(url.into(), template.into());
        }

        /// Returns whether a template URL is cached.
        pub fn contains(&self, url: &str) -> bool {
            self.templates.contains_key(url)
        }

        /// Removes a cached template by URL.
        pub fn remove(&mut self, url: &str) -> Option<String> {
            self.templates.remove(url)
        }

        /// Returns cached template count.
        pub fn len(&self) -> usize {
            self.templates.len()
        }

        /// Returns whether the cache is empty.
        pub fn is_empty(&self) -> bool {
            self.templates.is_empty()
        }
    }

