    /// Ergonomic async helpers for injected AngularTS `$templateRequest` values.
    pub trait TemplateRequestServiceExt {
        /// Fetches a template URL and resolves with template text.
        fn request_template(
            &self,
            url: &str,
        ) -> Pin<Box<dyn Future<Output = Result<String, JsValue>> + '_>>;
    }

    /// Ergonomic async helpers for injected AngularTS `$http` service values.
    pub trait HttpServiceExt {
        /// Sends a full `$http` request config and decodes the response body.
        fn request_json<T>(
            &self,
            config: &RequestConfig,
        ) -> Pin<Box<dyn Future<Output = Result<HttpResponse<T>, JsValue>> + '_>>
        where
            T: DeserializeOwned + 'static;

        /// Sends a `GET` request and decodes the response body.
        fn get_json<T>(
            &self,
            url: &str,
        ) -> Pin<Box<dyn Future<Output = Result<HttpResponse<T>, JsValue>> + '_>>
        where
            T: DeserializeOwned + 'static;

        /// Sends a `GET` request with shortcut options and decodes the response body.
        fn get_json_with<T>(
            &self,
            url: &str,
            config: &RequestShortcutConfig,
        ) -> Pin<Box<dyn Future<Output = Result<HttpResponse<T>, JsValue>> + '_>>
        where
            T: DeserializeOwned + 'static;

        /// Sends a `POST` request with a serializable body and decodes the response body.
        fn post_json<T, B>(
            &self,
            url: &str,
            body: &B,
        ) -> Pin<Box<dyn Future<Output = Result<HttpResponse<T>, JsValue>> + '_>>
        where
            T: DeserializeOwned + 'static,
            B: Serialize;

        /// Sends a `POST` request with shortcut options and decodes the response body.
        fn post_json_with<T, B>(
            &self,
            url: &str,
            body: &B,
            config: &RequestShortcutConfig,
        ) -> Pin<Box<dyn Future<Output = Result<HttpResponse<T>, JsValue>> + '_>>
        where
            T: DeserializeOwned + 'static,
            B: Serialize;
    }

    impl HttpServiceExt for JsValue {
        fn request_json<T>(
            &self,
            config: &RequestConfig,
        ) -> Pin<Box<dyn Future<Output = Result<HttpResponse<T>, JsValue>> + '_>>
        where
            T: DeserializeOwned + 'static,
        {
            let service = self.clone();
            let config = config.clone();

            Box::pin(async move {
                let request = service.unchecked_into::<Function>();
                let value = Reflect::apply(
                    &request,
                    &JsValue::UNDEFINED,
                    &Array::of1(&config.to_js_value()?),
                )?;
                let promise = value.dyn_into::<Promise>()?;

                decode_http_response(JsFuture::from(promise).await?)
            })
        }

        fn get_json<T>(
            &self,
            url: &str,
        ) -> Pin<Box<dyn Future<Output = Result<HttpResponse<T>, JsValue>> + '_>>
        where
            T: DeserializeOwned + 'static,
        {
            let service = self.clone();
            let url = url.to_string();

            Box::pin(async move {
                let service = service.unchecked_ref::<HttpService>();

                decode_http_response(JsFuture::from(service.get(&url)).await?)
            })
        }

        fn get_json_with<T>(
            &self,
            url: &str,
            config: &RequestShortcutConfig,
        ) -> Pin<Box<dyn Future<Output = Result<HttpResponse<T>, JsValue>> + '_>>
        where
            T: DeserializeOwned + 'static,
        {
            let service = self.clone();
            let url = url.to_string();
            let config = config.to_js_value();

            Box::pin(async move {
                let config = config?;
                let service = service.unchecked_ref::<HttpService>();

                decode_http_response(JsFuture::from(service.get_with_config(&url, &config)).await?)
            })
        }

        fn post_json<T, B>(
            &self,
            url: &str,
            body: &B,
        ) -> Pin<Box<dyn Future<Output = Result<HttpResponse<T>, JsValue>> + '_>>
        where
            T: DeserializeOwned + 'static,
            B: Serialize,
        {
            let service = self.clone();
            let url = url.to_string();
            let body = serde_wasm_bindgen::to_value(body)
                .map_err(|error| JsValue::from_str(&error.to_string()));

            Box::pin(async move {
                let body = body?;
                let service = service.unchecked_ref::<HttpService>();

                decode_http_response(JsFuture::from(service.post(&url, &body)).await?)
            })
        }

        fn post_json_with<T, B>(
            &self,
            url: &str,
            body: &B,
            config: &RequestShortcutConfig,
        ) -> Pin<Box<dyn Future<Output = Result<HttpResponse<T>, JsValue>> + '_>>
        where
            T: DeserializeOwned + 'static,
            B: Serialize,
        {
            let service = self.clone();
            let url = url.to_string();
            let body = serde_wasm_bindgen::to_value(body)
                .map_err(|error| JsValue::from_str(&error.to_string()));
            let config = config.to_js_value();

            Box::pin(async move {
                let body = body?;
                let config = config?;
                let service = service.unchecked_ref::<HttpService>();

                decode_http_response(
                    JsFuture::from(service.post_with_config(&url, &body, &config)).await?,
                )
            })
        }
    }

    impl TemplateRequestServiceExt for JsValue {
        fn request_template(
            &self,
            url: &str,
        ) -> Pin<Box<dyn Future<Output = Result<String, JsValue>> + '_>> {
            let service = self.clone();
            let url = url.to_string();

            Box::pin(async move {
                let request = service.unchecked_into::<Function>();
                let value = Reflect::apply(
                    &request,
                    &JsValue::UNDEFINED,
                    &Array::of1(&JsValue::from_str(&url)),
                )?;
                let promise = value.dyn_into::<Promise>()?;

                Ok(JsFuture::from(promise)
                    .await?
                    .as_string()
                    .unwrap_or_default())
            })
        }
    }

    impl TemplateRequestService {
        /// Fetches a template URL and resolves with template text.
        pub async fn request_template(&self, url: &str) -> Result<String, JsValue> {
            let request: &Function = self.unchecked_ref();
            let value = Reflect::apply(
                request,
                &JsValue::UNDEFINED,
                &Array::of1(&JsValue::from_str(url)),
            )?;
            let promise = value.dyn_into::<Promise>()?;

            Ok(JsFuture::from(promise)
                .await?
                .as_string()
                .unwrap_or_default())
        }
    }

    impl HttpService {
        /// Sends a full `$http` request config and decodes the response body.
        pub async fn request_json<T>(
            &self,
            config: &RequestConfig,
        ) -> Result<HttpResponse<T>, JsValue>
        where
            T: DeserializeOwned,
        {
            let service: &JsValue = self.as_ref();
            let request = service.clone().unchecked_into::<Function>();
            let value = Reflect::apply(
                &request,
                &JsValue::UNDEFINED,
                &Array::of1(&config.to_js_value()?),
            )?;
            let promise = value.dyn_into::<Promise>()?;
            decode_http_response(JsFuture::from(promise).await?)
        }

        /// Sends a `GET` request and decodes the response body.
        pub async fn get_json<T>(&self, url: &str) -> Result<HttpResponse<T>, JsValue>
        where
            T: DeserializeOwned,
        {
            decode_http_response(JsFuture::from(self.get(url)).await?)
        }

        /// Sends a `GET` request with shortcut options and decodes the response body.
        pub async fn get_json_with<T>(
            &self,
            url: &str,
            config: &RequestShortcutConfig,
        ) -> Result<HttpResponse<T>, JsValue>
        where
            T: DeserializeOwned,
        {
            decode_http_response(
                JsFuture::from(self.get_with_config(url, &config.to_js_value()?)).await?,
            )
        }

        /// Sends a `POST` request with a serializable body and decodes the response body.
        pub async fn post_json<T, B>(&self, url: &str, body: &B) -> Result<HttpResponse<T>, JsValue>
        where
            T: DeserializeOwned,
            B: Serialize,
        {
            let body = serde_wasm_bindgen::to_value(body)
                .map_err(|error| JsValue::from_str(&error.to_string()))?;
            decode_http_response(JsFuture::from(self.post(url, &body)).await?)
        }

        /// Sends a `POST` request with shortcut options and decodes the response body.
        pub async fn post_json_with<T, B>(
            &self,
            url: &str,
            body: &B,
            config: &RequestShortcutConfig,
        ) -> Result<HttpResponse<T>, JsValue>
        where
            T: DeserializeOwned,
            B: Serialize,
        {
            let body = serde_wasm_bindgen::to_value(body)
                .map_err(|error| JsValue::from_str(&error.to_string()))?;
            decode_http_response(
                JsFuture::from(self.post_with_config(url, &body, &config.to_js_value()?)).await?,
            )
        }
    }

    impl StateRegistryService {
        /// Registers a Rust-authored state declaration.
        pub fn register_state(&self, state: &StateDeclaration) -> Result<JsValue, JsValue> {
            Ok(self.register(&state.to_js_value()?))
        }
    }

    impl WebSocketService {
        /// Opens a managed WebSocket connection using Rust config builders.
        pub fn open(
            &self,
            url: &str,
            config: &WebSocketConfig,
        ) -> Result<WebSocketConnection, JsValue> {
            let service: &Function = self.unchecked_ref();
            let protocols = Array::new();

            for protocol in config.protocols() {
                protocols.push(&JsValue::from_str(protocol));
            }

            let value = Reflect::apply(
                service,
                &JsValue::UNDEFINED,
                &Array::of3(&JsValue::from_str(url), &protocols, &config.to_js_value()?),
            )?;

            value.dyn_into::<WebSocketConnection>()
        }
    }

    impl WebSocketConnection {
        /// Sends a serializable JSON message through the native WebSocket.
        pub fn send_json<T>(&self, data: &T) -> Result<(), JsValue>
        where
            T: Serialize,
        {
            let value = serde_wasm_bindgen::to_value(data)
                .map_err(|error| JsValue::from_str(&error.to_string()))?;
            self.websocket_send(&value);
            Ok(())
        }
    }

    impl SseService {
        /// Opens a managed SSE connection using Rust config builders.
        pub fn open(&self, url: &str, config: &SseConfig) -> Result<SseConnection, JsValue> {
            let service: &Function = self.unchecked_ref();
            let value = Reflect::apply(
                service,
                &JsValue::UNDEFINED,
                &Array::of2(&JsValue::from_str(url), &config.to_js_value()?),
            )?;

            value.dyn_into::<SseConnection>()
        }
    }

    impl RestFactory {
        /// Creates a REST resource client for a base URL.
        pub fn resource(
            &self,
            base_url: &str,
            options: Option<&RestOptions>,
        ) -> Result<RestService, JsValue> {
            let service: &Function = self.unchecked_ref();
            let args = Array::new();
            args.push(&JsValue::from_str(base_url));
            args.push(&JsValue::UNDEFINED);
            if let Some(options) = options {
                args.push(&options.to_js_value()?);
            }
            let value = Reflect::apply(service, &JsValue::UNDEFINED, &args)?;

            value.dyn_into::<RestService>()
        }
    }

    impl MachineService {
        /// Creates a JavaScript AngularTS machine from a JavaScript config object.
        pub fn create_from_js(&self, config: &JsValue) -> Result<BrowserMachine, JsValue> {
            let service: &Function = self.unchecked_ref();
            let value = Reflect::apply(service, &JsValue::UNDEFINED, &Array::of1(config))?;

            value.dyn_into::<BrowserMachine>()
        }
    }

    impl BrowserMachine {
        /// Sends an event to the JavaScript AngularTS machine.
        pub fn send_event(&self, event_type: &str, payload: Option<&JsValue>) -> bool {
            let machine: &JsValue = self.as_ref();
            let args = Array::new();
            args.push(&JsValue::from_str(event_type));
            if let Some(payload) = payload {
                args.push(payload);
            }

            let Ok(send) = Reflect::get(machine, &JsValue::from_str("send")) else {
                return false;
            };
            let Some(send) = send.dyn_ref::<Function>() else {
                return false;
            };

            Reflect::apply(send, machine, &args)
                .ok()
                .and_then(|value| value.as_bool())
                .unwrap_or(false)
        }
    }

    impl RestService {
        /// Fetches a collection and decodes the JSON response.
        pub async fn list_json<T>(&self) -> Result<Vec<T>, JsValue>
        where
            T: DeserializeOwned,
        {
            let value = JsFuture::from(self.rest_list()).await?;
            serde_wasm_bindgen::from_value(value)
                .map_err(|error| JsValue::from_str(&error.to_string()))
        }

        /// Fetches one resource by ID and decodes the JSON response.
        pub async fn get_json<T, ID>(&self, id: &ID) -> Result<T, JsValue>
        where
            T: DeserializeOwned,
            ID: Serialize,
        {
            let id = serde_wasm_bindgen::to_value(id)
                .map_err(|error| JsValue::from_str(&error.to_string()))?;
            let value = JsFuture::from(self.rest_get(&id)).await?;

            serde_wasm_bindgen::from_value(value)
                .map_err(|error| JsValue::from_str(&error.to_string()))
        }

        /// Creates a resource and decodes the JSON response.
        pub async fn create_json<T, B>(&self, body: &B) -> Result<T, JsValue>
        where
            T: DeserializeOwned,
            B: Serialize,
        {
            let body = serde_wasm_bindgen::to_value(body)
                .map_err(|error| JsValue::from_str(&error.to_string()))?;
            let value = JsFuture::from(self.rest_create(&body)).await?;

            serde_wasm_bindgen::from_value(value)
                .map_err(|error| JsValue::from_str(&error.to_string()))
        }
    }

